UPDATE reading_progress SET percentage_completed = #{percentageCompleted}, current_page = #{currentPage}, total_pages = #{totalPages}, current_position = COALESCE(#{currentPosition}, current_position), reading_time_minutes = #{readingTimeMinutes}, status = #{status}, last_read_at = #{lastReadAt}
, completed_at = #{completedAt}
